    protected void initCustVendTrans(CustVendTrans custVendTrans, LedgerVoucher _ledgerPostingJournal, boolean _useSubLedger)
    {
        LedgerJournalTrans ledgerJournalTrans;
        VendTrans vendTrans;

        next initCustVendTrans(custVendTrans,_ledgerPostingJournal,_useSubLedger);

        if (common.TableId == tablenum(LedgerJournalTrans))
        {
            ledgerJournalTrans = common;
            vendTrans = custVendTrans;

            vendTrans.UBSWarrantyRefInvoice = ledgerJournalTrans.UBSWarrantyRefInvoice;
        }
    }
